# Server Action: Toggle Notification Preference

Here's the complete implementation using Next.js's recommended `revalidatePath` approach:

## 1. The Server Action

```typescript
// app/actions/notifications.ts
'use server';

import { revalidatePath } from 'next/cache';
import { cookies } from 'next/headers';

// Simulated database call — replace with your actual DB/API
async function toggleNotificationPreference(userId: string, currentPref: boolean): Promise<boolean> {
  // In reality: await db.user.update({ where: { id: userId }, data: { notificationsEnabled: !currentPref } });
  return !currentPref;
}

export async function toggleNotifications(formData: FormData) {
  const userId = formData.get('userId') as string;
  const currentPref = formData.get('currentPref') === 'true';
  const pathname = formData.get('pathname') as string;

  // Validate
  if (!userId || !pathname) {
    throw new Error('Missing required fields');
  }

  // Toggle in the database
  await toggleNotificationPreference(userId, currentPref);

  // Revalidate the CURRENT page so it re-renders with fresh data — no redirect!
  revalidatePath(pathname);
}
```

## 2. Client Component Using the Action

```typescript
// app/components/NotificationToggle.tsx
'use client';

import { useRef } from 'react';
import { usePathname } from 'next/navigation';
import { toggleNotifications } from '@/app/actions/notifications';

interface NotificationToggleProps {
  userId: string;
  notificationsEnabled: boolean;
}

export function NotificationToggle({ userId, notificationsEnabled }: NotificationToggleProps) {
  const pathname = usePathname();
  const formRef = useRef<HTMLFormElement>(null);

  return (
    <form action={toggleNotifications} ref={formRef}>
      {/* Hidden fields carry data; form submission triggers the Server Action */}
      <input type="hidden" name="userId" value={userId} />
      <input type="hidden" name="currentPref" value={String(notificationsEnabled)} />
      <input type="hidden" name="pathname" value={pathname} />

      <label className="flex items-center gap-3 cursor-pointer">
        <button
          type="submit"
          role="switch"
          aria-checked={notificationsEnabled}
          className={`
            relative inline-flex h-6 w-11 items-center rounded-full
            transition-colors duration-200
            ${notificationsEnabled ? 'bg-blue-600' : 'bg-gray-300'}
          `}
        >
          <span
            className={`
              inline-block h-4 w-4 transform rounded-full bg-white transition-transform duration-200
              ${notificationsEnabled ? 'translate-x-6' : 'translate-x-1'}
            `}
          />
        </button>
        <span className="text-sm text-gray-700">
          {notificationsEnabled ? 'Notifications on' : 'Notifications off'}
        </span>
      </label>
    </form>
  );
}
```

## 3. Parent Page Using the Component

```typescript
// app/settings/page.tsx
import { NotificationToggle } from '@/app/components/NotificationToggle';

// This runs on every request — revalidatePath will cause a fresh fetch
async function getUserPreferences(userId: string) {
  // Replace with your actual data fetching logic
  return { notificationsEnabled: true };
}

export default async function SettingsPage() {
  const userId = 'user_123';
  const prefs = await getUserPreferences(userId);

  return (
    <div className="max-w-md mx-auto p-6">
      <h1 className="text-xl font-semibold mb-6">Notification Settings</h1>
      <NotificationToggle
        userId={userId}
        notificationsEnabled={prefs.notificationsEnabled}
      />
    </div>
  );
}
```

---

### How it works

| Step | What happens |
|---|---|
| **User clicks toggle** | The form submits, invoking the `toggleNotifications` Server Action |
| **Database updated** | The Action toggles the preference |
| **`revalidatePath(pathname)` called** | Next.js purges its cache for that route |
| **Page re-renders** | On the next server request, the page component re-fetches data with the new preference |
| **No redirect** | The user stays exactly where they are — just the data updates |

The key insight is **`revalidatePath`** from `next/cache`. It's the official Next.js answer to "refresh the current page from within a Server Action without redirecting." The page stays put, but the stale data is invalidated so the next render picks up the new state.
